#!/usr/bin/env python3
from __future__ import annotations

import json
import sys
from pathlib import Path

ROOT = Path(__file__).resolve().parents[1]
LABELS_PATH = ROOT / "homepage" / "data" / "countries.json"
OUT = ROOT / "homepage" / "data" / "country-snapshots.json"
FEATURED_LIMIT = 6
POSITION_LIMIT = 8
CITY_LIMIT = 8


def _load_marketing_keys() -> list[str]:
    if not LABELS_PATH.is_file():
        return ["germany", "ireland", "netherlands", "portugal", "uk"]
    raw = json.loads(LABELS_PATH.read_text(encoding="utf-8"))
    if not isinstance(raw, dict):
        return []
    return sorted(key for key in raw if isinstance(key, str) and key.strip())


def _city_labels(companies: list[dict]) -> list[str]:
    seen: set[str] = set()
    cities: list[str] = []
    for company in companies:
        for loc in company.get("locations") or []:
            city = (loc.get("city") or "").strip()
            if not city:
                continue
            key = city.casefold()
            if key in seen:
                continue
            seen.add(key)
            cities.append(city)
            if len(cities) >= CITY_LIMIT:
                return cities
        city_field = (company.get("city") or "").strip()
        if city_field and "·" not in city_field:
            bare = city_field.split("(")[0].strip()
            key = bare.casefold()
            if bare and key not in seen:
                seen.add(key)
                cities.append(bare)
                if len(cities) >= CITY_LIMIT:
                    return cities
    return cities


def _snapshot_for_country(country: str, overview_row: dict | None, meta_row: dict | None) -> dict:
    from relocation_jobs.web.routes.public import _public_preview_payload

    preview = _public_preview_payload(limit=FEATURED_LIMIT, country=country, search=None)
    companies = list(preview.get("companies") or [])
    featured = list(preview.get("featured_companies") or [])
    featured_scope = (preview.get("meta") or {}).get("featured_scope") or ""
    if featured_scope != "country":
        featured = []
    positions = [
        {
            "title": row.get("title") or "",
            "company_name": row.get("company_name") or "",
            "location": row.get("location") or "",
            "url": row.get("url") or "",
        }
        for row in (preview.get("positions") or [])[:POSITION_LIMIT]
        if (row.get("country") or "").strip().lower() == country
    ]
    sample_companies = [
        {
            "name": row.get("name") or "",
            "city": row.get("city") or "",
            "careers_url": row.get("careers_url") or "",
            "job_count": int(row.get("job_count") or 0),
            "visa_job_count": int(row.get("visa_job_count") or 0),
        }
        for row in companies[:FEATURED_LIMIT]
    ]
    if not sample_companies and featured:
        sample_companies = [
            {
                "name": row.get("name") or "",
                "city": row.get("city") or "",
                "careers_url": row.get("careers_url") or "",
                "job_count": 0,
                "visa_job_count": int(row.get("visa_role_count") or 0),
            }
            for row in featured[:FEATURED_LIMIT]
        ]
    row = overview_row or {}
    meta = meta_row or {}
    return {
        "country": country,
        "label": row.get("label") or meta.get("label") or country,
        "companies": int(row.get("companies") or 0),
        "jobs": int(row.get("jobs") or 0),
        "visa_jobs": int(row.get("visa_jobs") or 0),
        "last_fetch": meta.get("last_fetch") or meta.get("updated") or "",
        "cities": _city_labels(companies),
        "sample_companies": sample_companies,
        "sample_positions": positions,
    }


def main() -> int:
    sys.path.insert(0, str(ROOT))
    try:
        from dotenv import load_dotenv
    except ImportError:
        load_dotenv = None
    if load_dotenv is not None:
        load_dotenv(ROOT / ".env")

    from relocation_jobs.catalog.repo import get_catalog_overview

    keys = _load_marketing_keys()
    overview = get_catalog_overview()
    by_country = {
        row.get("country"): row
        for row in overview.get("countries") or []
        if row.get("country")
    }
    meta_by_country = {
        row.get("country"): row
        for row in overview.get("country_meta") or []
        if row.get("country")
    }
    snapshots = {
        key: _snapshot_for_country(key, by_country.get(key), meta_by_country.get(key))
        for key in keys
    }
    OUT.parent.mkdir(parents=True, exist_ok=True)
    payload = {
        "generated_note": "Build-time catalog snapshot for country marketing pages.",
        "countries": snapshots,
    }
    OUT.write_text(json.dumps(payload, indent=2, ensure_ascii=False) + "\n", encoding="utf-8")
    print(f"Wrote {len(snapshots)} country snapshots to {OUT}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())

import snapshotsJson from "@/data/country-snapshots.json";

export type CountrySampleCompany = {
  name: string;
  city: string;
  careers_url: string;
  job_count: number;
  visa_job_count: number;
};

export type CountrySamplePosition = {
  title: string;
  company_name: string;
  location: string;
  url: string;
};

export type CountrySnapshot = {
  country: string;
  label: string;
  companies: number;
  jobs: number;
  visa_jobs: number;
  last_fetch: string;
  cities: string[];
  sample_companies: CountrySampleCompany[];
  sample_positions: CountrySamplePosition[];
};

type SnapshotsFile = {
  countries: Record<string, CountrySnapshot>;
};

const DATA = snapshotsJson as SnapshotsFile;

export function countrySnapshot(key: string): CountrySnapshot | null {
  return DATA.countries[key] ?? null;
}

"use client";

import { useEffect, useState } from "react";
import { Card } from "@/components/ui/Card";
import { Button } from "@/components/ui/Button";
import type { CountrySnapshot } from "@/lib/country-snapshots";

type Props = {
  country: string;
  label: string;
  initial: CountrySnapshot | null;
};

type LiveState = {
  companies: number;
  jobs: number;
  visa_jobs: number;
  cities: string[];
  sample_companies: CountrySnapshot["sample_companies"];
  sample_positions: CountrySnapshot["sample_positions"];
  last_fetch: string;
  source: "live" | "snapshot" | "empty";
};

function emptyState(label: string): LiveState {
  return {
    companies: 0,
    jobs: 0,
    visa_jobs: 0,
    cities: [],
    sample_companies: [],
    sample_positions: [],
    last_fetch: "",
    source: "empty",
  };
}

function fromSnapshot(snapshot: CountrySnapshot | null, label: string): LiveState {
  if (!snapshot) {
    return emptyState(label);
  }
  const hasData =
    snapshot.companies > 0 ||
    snapshot.sample_companies.length > 0 ||
    snapshot.sample_positions.length > 0;
  return {
    companies: snapshot.companies,
    jobs: snapshot.jobs,
    visa_jobs: snapshot.visa_jobs,
    cities: snapshot.cities,
    sample_companies: snapshot.sample_companies,
    sample_positions: snapshot.sample_positions,
    last_fetch: snapshot.last_fetch,
    source: hasData ? "snapshot" : "empty",
  };
}

function formatFetch(value: string): string {
  if (!value) return "";
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return value;
  return date.toLocaleString("en-GB", {
    day: "numeric",
    month: "short",
    year: "numeric",
  });
}

export function CountryCatalogPanel({ country, label, initial }: Props) {
  const [state, setState] = useState<LiveState>(() => fromSnapshot(initial, label));

  useEffect(() => {
    let cancelled = false;

    async function load() {
      try {
        const [overviewRes, previewRes] = await Promise.all([
          fetch("/api/public/overview"),
          fetch(`/api/public/preview?country=${encodeURIComponent(country)}&limit=8`),
        ]);
        if (!overviewRes.ok || !previewRes.ok) return;
        const overview = await overviewRes.json();
        const preview = await previewRes.json();
        if (cancelled) return;

        const row = (overview.countries || []).find(
          (item: { country?: string }) => item.country === country,
        );
        const meta = (overview.country_meta || []).find(
          (item: { country?: string }) => item.country === country,
        );
        const companies = (preview.companies || []) as Array<{
          name?: string;
          city?: string;
          careers_url?: string;
          job_count?: number;
          visa_job_count?: number;
          locations?: Array<{ city?: string }>;
        }>;
        const featuredScope = preview.meta?.featured_scope || "";
        const featured =
          featuredScope === "country"
            ? ((preview.featured_companies || []) as Array<{
                name?: string;
                city?: string;
                careers_url?: string;
                visa_role_count?: number;
              }>)
            : [];
        const positions = ((preview.positions || []) as Array<{
          title?: string;
          company_name?: string;
          location?: string;
          url?: string;
          country?: string;
        }>)
          .filter((item) => (item.country || "").toLowerCase() === country)
          .slice(0, 8)
          .map((item) => ({
            title: item.title || "",
            company_name: item.company_name || "",
            location: item.location || "",
            url: item.url || "",
          }));

        const citySeen = new Set<string>();
        const cities: string[] = [];
        for (const company of companies) {
          for (const loc of company.locations || []) {
            const city = (loc.city || "").trim();
            const key = city.toLowerCase();
            if (!city || citySeen.has(key)) continue;
            citySeen.add(key);
            cities.push(city);
            if (cities.length >= 8) break;
          }
          if (cities.length >= 8) break;
        }

        let sampleCompanies = companies.slice(0, 6).map((item) => ({
          name: item.name || "",
          city: item.city || "",
          careers_url: item.careers_url || "",
          job_count: Number(item.job_count || 0),
          visa_job_count: Number(item.visa_job_count || 0),
        }));
        if (!sampleCompanies.length && featured.length) {
          sampleCompanies = featured.slice(0, 6).map((item) => ({
            name: item.name || "",
            city: item.city || "",
            careers_url: item.careers_url || "",
            job_count: 0,
            visa_job_count: Number(item.visa_role_count || 0),
          }));
        }

        const next: LiveState = {
          companies: Number(row?.companies || 0),
          jobs: Number(row?.jobs || 0),
          visa_jobs: Number(row?.visa_jobs || 0),
          cities,
          sample_companies: sampleCompanies,
          sample_positions: positions,
          last_fetch: meta?.last_fetch || meta?.updated || "",
          source:
            Number(row?.companies || 0) > 0 ||
            sampleCompanies.length > 0 ||
            positions.length > 0
              ? "live"
              : "empty",
        };
        setState(next);
      } catch {
        /* keep snapshot */
      }
    }

    load();
    return () => {
      cancelled = true;
    };
  }, [country]);

  const fetchLabel = formatFetch(state.last_fetch);

  return (
    <section className="mt-12" aria-labelledby="catalog-data-heading">
      <div className="flex flex-wrap items-end justify-between gap-3">
        <div>
          <p className="section-kicker">Live catalog · {label}</p>
          <h2
            id="catalog-data-heading"
            className="font-display text-2xl font-semibold text-text-primary"
          >
            What is on the board right now
          </h2>
        </div>
        {fetchLabel ? (
          <p className="text-xs text-text-muted">Last catalog activity {fetchLabel}</p>
        ) : null}
      </div>

      {state.source === "empty" ? (
        <Card className="mt-5 px-5 py-6">
          <p className="text-sm leading-relaxed text-text-secondary">
            The {label} catalog is still thin or empty in this environment. Open
            the board anyway — new companies appear after scheduled career-page
            refreshes.
          </p>
          <Button
            as="a"
            href={`/panel?country=${country}`}
            variant="primary"
            className="mt-4"
          >
            Open {label} board
          </Button>
        </Card>
      ) : (
        <>
          <div className="country-stat-rail mt-5" aria-label={`${label} catalog counts`}>
            <div>
              <strong>{state.companies}</strong>
              <span>Companies tracked</span>
            </div>
            <div>
              <strong>{state.jobs}</strong>
              <span>Open roles indexed</span>
            </div>
            <div>
              <strong>{state.visa_jobs}</strong>
              <span>Positive sponsorship signals</span>
            </div>
          </div>

          {state.cities.length > 0 ? (
            <div className="mt-6">
              <h3 className="font-display text-lg font-semibold text-text-primary">
                Cities appearing in {label} listings
              </h3>
              <ul className="country-chip-row mt-3">
                {state.cities.map((city) => (
                  <li key={city}>{city}</li>
                ))}
              </ul>
            </div>
          ) : null}

          {state.sample_companies.length > 0 ? (
            <div className="mt-8">
              <h3 className="font-display text-lg font-semibold text-text-primary">
                Sample companies in {label}
              </h3>
              <ul className="mt-4 grid gap-3">
                {state.sample_companies.map((company) => (
                  <li key={company.name}>
                    <Card className="px-4 py-4">
                      <div className="flex flex-wrap items-start justify-between gap-2">
                        <div>
                          <p className="font-display text-base font-semibold text-text-primary">
                            {company.name}
                          </p>
                          {company.city ? (
