.landing-band-mcp {
  background:
    linear-gradient(
      160deg,
      color-mix(in srgb, var(--color-accent) 10%, var(--color-paper)) 0%,
      var(--color-paper-2) 48%,
      var(--color-paper) 100%
    );
  border-block: var(--rule-width) solid var(--border-subtle);
}

.country-stat-rail {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: var(--space-sm);
  border: var(--rule-width) solid var(--color-rule);
  border-radius: var(--radius-card);
  background: var(--color-paper-2);
  overflow: clip;
}

.country-stat-rail > div {
  display: grid;
  gap: 0.2rem;
  padding: var(--space-md) var(--space-sm);
  min-width: 0;
}

.country-stat-rail > div:not(:last-child) {
  border-right: var(--rule-width) solid var(--color-rule);
}

.country-stat-rail strong {
  font-family: var(--font-display);
  font-size: clamp(1.5rem, 2vw + 0.75rem, 2rem);
  font-weight: 700;
  letter-spacing: -0.03em;
  color: var(--color-ink);
  overflow-wrap: anywhere;
}

.country-stat-rail span {
  color: var(--text-muted);
  font-size: 0.6875rem;
  font-weight: 500;
  letter-spacing: 0.04em;
  line-height: 1.35;
  text-transform: uppercase;
}

.country-chip-row {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-2xs);
  margin: 0;
  padding: 0;
  list-style: none;
}

.country-chip-row li {
  border: var(--rule-width) solid var(--color-rule);
  border-radius: var(--radius-pill);
  background: var(--color-paper);
  color: var(--text-secondary);
  font-size: 0.8125rem;
  font-weight: 600;
  padding: 0.4rem 0.75rem;
}

@media (max-width: 639px) {
  .country-stat-rail {
    grid-template-columns: 1fr;
  }

  .country-stat-rail > div:not(:last-child) {
    border-right: 0;
    border-bottom: var(--rule-width) solid var(--color-rule);
  }
}

